// Script Continued Below
g_OUHA_responsible = {};
var OrganizationalScripts = Class.create();
OrganizationalScripts.prototype = {
	initialize: function() {
	},

	// STRY0140267 - get the members with Tasking Authority from the current Org Structure only
	setTopOUTaskAdministrators: function(current){
		var orgUser = current.getUniqueValue();
		var ouMemberRecords = new GlideRecordSecure("x_153465_discovert_discover_office_members");
		ouMemberRecords.addQuery("u_organizational_user", orgUser);
		ouMemberRecords.query();
		while(ouMemberRecords.next()){
			// STRY0140267 - get the members with Tasking Authority from the current Org Structure only
			var memberOU = ouMemberRecords.getValue("discover_office_hierarchy");
			this.setTopOUTaskAdministratorsForOU(memberOU);
		}
	},

	// STRY0140267 - get the members with Tasking Authority from the current Org Structure only
	setTopOUTaskAdministratorsForOU:function(ouId){
		//first, calculate all GTA members
		var ouMemberRecords = new GlideRecordSecure("x_153465_discovert_discover_office_members");
		var grMemberOU = new GlideRecordSecure("x_153465_discovert_discover_office_hierarchy");
		var topOU = "";
		if(grMemberOU.get(ouId)){
			topOU = grMemberOU.getValue("u_top_ou");
		}
		ouMemberRecords.addQuery("discover_office_hierarchy.u_top_ou", topOU);
		ouMemberRecords.addQuery("u_organizational_user.is_task_administrator", true);
		// sorted by office member name
		ouMemberRecords.orderBy("office_member.name");
		ouMemberRecords.query();
		var ouMembers = '';
		// accumulate all global ta members to a variable
		while (ouMemberRecords.next()) {
			if (ouMembers === '') {
				ouMembers = ouMemberRecords.office_member;
			} else {
				ouMembers = ouMembers + "," + ouMemberRecords.office_member;
			}
		}
		//remove duplicates from the list Global Tasking Authorities
		var lyst = ouMembers.split(",");
		var dupes = {};
		for (var x = 0; x < lyst.length; x++) {
			if (!dupes[lyst[x]]) {
				dupes[lyst[x]] = lyst[x];
			}
		}
		var keys = Object.keys(dupes);
		var gta_list = keys.toString();
		//next set all ou with the same variable
		// STRY0140267 - set tasking authorities on top ou only
		var orgUnit = new GlideRecord('x_153465_discovert_discover_office_hierarchy');
		orgUnit.addQuery("u_top_ou", topOU);
		orgUnit.query();
		while (orgUnit.next()) {
			orgUnit.u_global_authorities = gta_list;
			orgUnit.update();
		}

	},
	//---------------------------------------------------------------------------------------------
	// Get ancestors for OUs
	// STRY0137140 - added to simplify queries and improve performance
	//---------------------------------------------------------------------------------------------
	getAncestors: function(parentId) {
		var answer = '';
		var grOU = new GlideRecord('x_153465_discovert_discover_office_hierarchy');
		if(parentId && grOU.get(parentId)){
			var nextParentId = grOU.getValue("parent");
			if(nextParentId != null && nextParentId != ""){
				answer = parentId + "," + this.getAncestors(nextParentId);
			} else {
				answer = parentId;
			}
		}
		return answer;
	},

	// STRY0116823 - Returns the topOU for a given OU
	getTopOUId: function(strOUId)
	{
		var retOffice;
		var gr_office = new GlideRecordSecure('x_153465_discovert_discover_office_hierarchy');
		if(gr_office.get(strOUId)){
			retOffice = gr_office.getValue('u_top_ou') + '';
		}
		return retOffice + '';
	},

	// STRY0059849 - OU Roles - OU Hierarchy Administrator
	getOUHA_responsible: function(OUID)
	{
		if(typeof g_OUHA_responsible != undefined){
			if(g_OUHA_responsible.OU != undefined){
				if(g_OUHA_responsible.OU.value != undefined){
					if(g_OUHA_responsible.OU.value == OUID){
						// TODO - may need to do a quick time check here and reset if older than 5 min - or, just let the advice to user be select different OU and come back
						return g_OUHA_responsible;
					}
				}
			}
		}
		g_OUHA_responsible = this.getOUHA_responsibleRecurse(OUID);
		return g_OUHA_responsible;
	},
	getOUHA_responsibleRecurse: function(OUID)
	{
		var OUHA_responsible = {};
		OUHA_responsible.OU = {};
		// DFCT0010769 - constructor change so Administrators and GlobalAdministrators objects always have value and displayValue properties
		OUHA_responsible.Administrators = {value: '', displayValue: ''};
		OUHA_responsible.GlobalAdministrators = {value: '', displayValue: ''};
		var grOU = new GlideRecord('x_153465_discovert_discover_office_hierarchy');
		if(grOU.get(OUID)){
			if(grOU.u_ou_hierarchy_administrators + '' != ''){
				OUHA_responsible.Administrators.value = grOU.getValue('u_ou_hierarchy_administrators');
				OUHA_responsible.Administrators.displayValue = grOU.getDisplayValue('u_ou_hierarchy_administrators');
			} else {
				// if not found go to parent until found or at top
				if(grOU.parent + '' != ''){
					OUHA_responsible = this.getOUHA_responsible(grOU.parent);
				} else {
					// if here, then reached the top and did not find OUHA, load Global Hierarchy 
					// If here, set the GHA, there might be GHA, but this may not be set
					var grUserRoles = new GlideRecord('sys_user_has_role');  
					grUserRoles.addEncodedQuery('^role.name=x_153465_discovert.tasker_organizational_admin^state=active^user.active=true');
					grUserRoles.query();
					var aGlobalAdministratorsValue = [];
					var aGlobalAdministratorsDisplayValue = [];
					while(grUserRoles.next()) {
						aGlobalAdministratorsValue.push(grUserRoles.getValue('user')); 
						aGlobalAdministratorsDisplayValue.push(grUserRoles.getDisplayValue('user'));
					}
					OUHA_responsible.GlobalAdministrators.value=aGlobalAdministratorsValue.join(',');
					OUHA_responsible.GlobalAdministrators.displayValue=aGlobalAdministratorsDisplayValue.join(',');
					// OUHAs were not found, so set to blank
					OUHA_responsible.Administrators.value='';
					OUHA_responsible.Administrators.displayValue='';
				}
			}
			// set this at the end to reset back to the base calling OU after any recursion
			OUHA_responsible.OU.displayValue = grOU.getDisplayValue();
		}
		// set this at the end to reset back to the base calling OU after any recursion
		OUHA_responsible.OU.value = OUID;
		return OUHA_responsible;
	},
		//RJ -STRY0074663
	saveContactInfo: function(contactData)
	{
		var success = false;
		var bHaveContact = false;
		var grUserInfo;
		var sError = '';
		var oContactData = JSON.parse(contactData);
		if(oContactData.userId){
			bHaveContact = true;
			// TODO, NEED DECISION FROM EVAN ON WHERE/HOW TO STORE
			// update the user Info or the table x_153465_discovert_external_poc_info 
			// may want to check if the user can insert into the User table
			grUserInfo = new GlideRecordSecure('sys_user');
			if(grUserInfo.get(oContactData.userId)){
				// found user, udpate information if possible
				if(grUserInfo.canWrite()){
					grUserInfo.first_name = oContactData.first_name;
					grUserInfo.last_name = oContactData.last_name;
					grUserInfo.title = oContactData.title;
					grUserInfo.email = oContactData.email;
					grUserInfo.mobile_phone = oContactData.mobile_phone;
					grUserInfo.phone = oContactData.phone;
					grUserInfo.update();
					bHaveContact = true;
				}else{
					sError = 'The user ' + gs.getUserName() + ' does not have permissions to update the User in: ' + grUserInfo.getRecordClassName();
					gs.addErrorMessage(sError);
					gs.error(sError);
				}
			}
		}

		// Update or Insert the Tasker Contact table record to write the Note
		if(bHaveContact){
			// check to see if there is a Tasker Contact for this user.
			var grTaskerContact = new GlideRecordSecure('x_153465_discovert_tasker_contacts');
			grTaskerContact.addQuery('u_contact', oContactData.userId);
			grTaskerContact.query();
			var sTaskerContactId;
			if(grTaskerContact.next()){
				// there is a contract record, update the note.
				grTaskerContact.u_contact_notes = oContactData.u_contact_notes;
				sTaskerContactId = grTaskerContact.getUniqueValue();
				grTaskerContact.update();
			}else{
				// the the Tasker Contact record for this user doesn't exist, create it to save the note.
				grTaskerContact.initialize();
				grTaskerContact.u_contact = oContactData.userId;
				grTaskerContact.u_contact_notes = oContactData.u_contact_notes;
				sTaskerContactId = grTaskerContact.insert();
			}
			var grOUContact = new GlideRecordSecure('x_153465_discovert_organizational_contacts');
			grOUContact.addQuery('u_user_information', oContactData.userId);
			grOUContact.addQuery('u_contact_ou', oContactData.u_contact_ou);
			grOUContact.query();
			if(grOUContact.next()){
				// if this is an insert, the OU already has this contact, raise an error down
				if(oContactData.ou_contact_row_id == -1){
					sError = 'The contact selected is already in this OU.  Please select a different contact.';
					gs.addErrorMessage(sError);
				}else if(grOUContact.getUniqueValue() != oContactData.ou_contact_row_id){
					// an update is being performed that matches an OU / user combination that is already on this OU raise an error
					sError = 'The update attempted by the user would create a duplicate Contact and OU combination.  Please select a different contact.';
					gs.addErrorMessage(sError);
				}else{
					// user is performing an update that changes information, but does not create a duplicate
					grOUContact.u_user_information = oContactData.userId;
					grOUContact.u_contact_ou = oContactData.u_contact_ou;
					grOUContact.u_tasker_contact = sTaskerContactId;
					grOUContact.update();
				}
			}else{
				// OU and Contact relationship not found
				if(oContactData.ou_contact_row_id == -1){
					grOUContact.initialize();
					grOUContact.u_user_information = oContactData.userId;
					grOUContact.u_contact_ou = oContactData.u_contact_ou;
					grOUContact.u_tasker_contact = sTaskerContactId;
					grOUContact.insert();
				}else{
					// update is being performed and the OU - Contact relationship is changing to another combination that does not create a duplicate
					// If the action is update, then, do a get instead of a query and use the ID from the OU Contact
					if(grOUContact.get(oContactData.ou_contact_row_id)){
						// user is performing an update that changes information, but does not create a duplicate
						grOUContact.u_user_information = oContactData.userId;
						grOUContact.u_contact_ou = oContactData.u_contact_ou;
						grOUContact.u_tasker_contact = sTaskerContactId;
						grOUContact.update();
					}
				}
			}
		}
		success = answer == '' ? true: false;
		return success;
	},

	//RJ -STRY0074663
	getContactNote: function(strContactId)
	{
		var retContactNote;
		var grContactNote = new GlideRecordSecure('x_153465_discovert_tasker_contacts');
		grContactNote.addQuery('u_contact',strContactId);
		grContactNote.query();
		if(grContactNote.next()){
			retContactNote = grContactNote.u_contact_notes;
		}else{
			retContactNote = '';
		}
		return retContactNote;
	},

	//KT Added to resolve the bug of leaving the Member as Taskig Authority when it is deleted from an OU
	RemoveMemberAsTaskingAuthority: function(strOU, strUserId)
	{ 
		// STRY0046028, STRY0085149
		// NOTE: Glide Record secure did NOT work here, the user may have rights to remove a member, but not rights to update the OU
		var grOU = new GlideRecord('x_153465_discovert_discover_office_hierarchy');
		grOU.addQuery('sys_id',strOU);
		grOU.query();
		if(grOU.next()){
			var tasking_authorities = grOU.tasking_authorities + '';
			grOU.tasking_authorities = tasking_authorities.replaceAll(strUserId, '');
			grOU.update();
		}
		return;
	},
	//STRY0059849 - making OU HA similar to TM
	RemoveMemberAsOUHierarchyAdmin: function(strOU, strUserId)
	{ 
		// STRY0046028, STRY0085149
		// NOTE: Glide Record secure did NOT work here, the user may have rights to remove a member, but not rights to update the OU
		var grOU = new GlideRecord('x_153465_discovert_discover_office_hierarchy');
		grOU.addQuery('sys_id',strOU);
		grOU.query();
		if(grOU.next()){
			var ou_hierarchy_Amin = grOU.u_ou_hierarchy_administrators + '';
			grOU.u_ou_hierarchy_administrators = ou_hierarchy_Amin.replaceAll(strUserId, '');
			grOU.update();
		}
		return;
	},	

	// STRY0132318 Returns the display value for the default ou for a given user.
	GetDisplayValueUserDefaultOU: function(strUserId)
	{
		// STRY0131148 move to org User table
		var orgUserQuery = new GlideRecordSecure('x_153465_discovert_organization_user');
		orgUserQuery.addQuery('u_tasker_user',strUserId);
		orgUserQuery.query();
		var retOffice;
		if(orgUserQuery.next()){
			retOffice = orgUserQuery.getDisplayValue('u_default_ou') + '';
		}
		return retOffice + '';
	},

	// Returns the default ou for a given user.
	GetUserDefaultOU: function(strUserId)
	{
		// STRY0131148 move to org User table
		var orgUserQuery = new GlideRecordSecure('x_153465_discovert_organization_user');
		orgUserQuery.addQuery('u_tasker_user',strUserId);
		orgUserQuery.query();
		var retOffice;
		if(orgUserQuery.next()){
			retOffice = orgUserQuery.getValue('u_default_ou') + '';
		}
		return retOffice + '';
	},

	GetUserDefaultTaskingAuthority: function(strOU)
	{
		// set to eliminate error in the log
		var retTaskingAuthority = "";
		// look up this OU in the Tasking Authority list...
		// If it exists, default the Tasking Authority to this OU, if not, return blank
		var TaskingAuthorityQuery = new GlideRecordSecure('x_153465_discovert_discover_office_hierarchy');
		TaskingAuthorityQuery.addQuery('sys_id',strOU);
		TaskingAuthorityQuery.addQuery('includeintaskingauthority',true);

		TaskingAuthorityQuery.query();
		if(TaskingAuthorityQuery.next()){

			retTaskingAuthority = TaskingAuthorityQuery.sys_id;
		}
		return retTaskingAuthority;
	},
// 	// RAJ 2018-07-19 - STRY0012696 - added this to remove the getReference calls
// 	getTaskingAuthorityOrganizationalUnit: function(strTaskingAuthority)
// 	{
// 		var retTaskingAuthority;

// 		// look up this OU in the Tasking Authority list...
// 		// If it exists, default the Tasking Authority to this OU, if not, return blank
// 		var TaskingAuthorityQuery = new GlideRecordSecure('x_153465_discovert_tasking_authority');
// 		if(TaskingAuthorityQuery.get(strTaskingAuthority)){
// 			retTaskingAuthority = TaskingAuthorityQuery.organizational_unit;
// 		}
// 		return retTaskingAuthority;
// 	},

	// RAJ 2018-07-19 - STRY0012696 - added this to remove the getReference calls
	getOrganizationalUnitAbbrAndName: function(strOU)
	{
		var retAbbrAndName;

		// look up this OU in the Tasking Authority list...
		// If it exists, default the Tasking Authority to this OU, if not, return blank
		var grOU = new GlideRecordSecure('x_153465_discovert_discover_office_hierarchy');
		// STRY0072771 - Certification Debt
		if(grOU.get(strOU)){
			retAbbrAndName = grOU.office_abbreviation + '9999_9999' + grOU.office_name;
		}
		return retAbbrAndName;
	},

	type: 'OrganizationalScripts'
};
